struct GoogleMapView: UIViewRepresentable {
    @Binding var center: CLLocationCoordinate2D
    @Binding var pin: CLLocationCoordinate2D
    @Binding var zoom: Float

    func makeCoordinator() -> Coordinator {
        Coordinator(self)
    }

    func makeUIView(context: Context) -> GMSMapView {
        let camera = GMSCameraPosition.camera(withTarget: center, zoom: zoom)
        let mapView = GMSMapView(frame: .zero, camera: camera)
        mapView.delegate = context.coordinator
        mapView.settings.compassButton = true
        mapView.settings.myLocationButton = false
        mapView.isMyLocationEnabled = false

        let marker = GMSMarker(position: pin)
        marker.title = "Demo Pin"
        marker.snippet = "Tap to move"
        marker.map = mapView
        context.coordinator.marker = marker

        return mapView
    }

    func updateUIView(_ mapView: GMSMapView, context: Context) {
        if abs(mapView.camera.target.latitude - center.latitude) > 0.00001 ||
            abs(mapView.camera.target.longitude - center.longitude) > 0.00001 ||
            abs(mapView.camera.zoom - zoom) > 0.01 {
            mapView.animate(to: GMSCameraPosition.camera(withTarget: center, zoom: zoom))
        }

        if let marker = context.coordinator.marker {
            if abs(marker.position.latitude - pin.latitude) > 0.00001 ||
                abs(marker.position.longitude - pin.longitude) > 0.00001 {
                marker.position = pin
            }
        }
    }

    final class Coordinator: NSObject, GMSMapViewDelegate {
        var parent: GoogleMapView
        weak var marker: GMSMarker?

        init(_ parent: GoogleMapView) {
            self.parent = parent
        }

        func mapView(_ mapView: GMSMapView, idleAt position: GMSCameraPosition) {
            parent.center = position.target
            parent.zoom = position.zoom
        }

        func mapView(_ mapView: GMSMapView, didTapAt coordinate: CLLocationCoordinate2D) {
            parent.pin = coordinate
        }

        func mapView(_ mapView: GMSMapView, didTap marker: GMSMarker) -> Bool {
            parent.pin = marker.position
            return false
        }
    }
}

