final class PaymentsDemoModel: ObservableObject {
    @Published var amountDollars: Double = 12
    @Published var itemName: String = "Demo Ride"
    @Published var statusText: String = "Ready."
    @Published var isLoading: Bool = false
    @Published var isPresentingSheet: Bool = false

    var paymentSheet: PaymentSheet?

    func startCheckout() {
        isLoading = true
        statusText = "Preparing checkout…"

        DispatchQueue.main.asyncAfter(deadline: .now() + 0.6) {
            let clientSecret = "pi_demo_client_secret_DO_NOT_USE"
            var configuration = PaymentSheet.Configuration()
            configuration.merchantDisplayName = "Demo Company"
            configuration.allowsDelayedPaymentMethods = true

            self.paymentSheet = PaymentSheet(paymentIntentClientSecret: clientSecret, configuration: configuration)
            self.isLoading = false
            self.statusText = "Presenting Payment Sheet (demo)…"
            self.isPresentingSheet = true
        }
    }

    func handle(result: PaymentSheetResult) {
        isPresentingSheet = false
        switch result {
        case .completed:
            statusText = "Payment completed (demo)."
        case .canceled:
            statusText = "Payment canceled."
        case .failed(let error):
            statusText = "Payment failed: \(error.localizedDescription)"
        }
    }
}

struct PaymentSheetHostView: UIViewControllerRepresentable {
    let paymentSheet: PaymentSheet?
    let onResult: (PaymentSheetResult) -> Void

    func makeUIViewController(context: Context) -> UIViewController {
        HostController(paymentSheet: paymentSheet, onResult: onResult)
    }

    func updateUIViewController(_ uiViewController: UIViewController, context: Context) {}

    final class HostController: UIViewController {
        let paymentSheet: PaymentSheet?
        let onResult: (PaymentSheetResult) -> Void
        private var didPresent = false

        init(paymentSheet: PaymentSheet?, onResult: @escaping (PaymentSheetResult) -> Void) {
            self.paymentSheet = paymentSheet
            self.onResult = onResult
            super.init(nibName: nil, bundle: nil)
            view.backgroundColor = .systemBackground
        }

        required init?(coder: NSCoder) { fatalError("init(coder:) has not been implemented") }

        override func viewDidAppear(_ animated: Bool) {
            super.viewDidAppear(animated)
            guard !didPresent else { return }
            didPresent = true

            guard let paymentSheet else {
                onResult(.failed(NSError(domain: "Demo", code: -1, userInfo: [NSLocalizedDescriptionKey: "PaymentSheet not configured."])))
                dismiss(animated: true)
                return
            }

            paymentSheet.present(from: self) { result in
                self.onResult(result)
                self.dismiss(animated: true)
            }
        }
    }
}

